args.query:
SELECT em.id, em.subject, em.textbody, em.messagedate, em.fromaddress, em.toids, em.parentid
FROM emailmessage em
WHERE TRIM(REPLACE(em.relatedtoid,'#','')) IN (
  SELECT id FROM "Case" WHERE TRIM(REPLACE(contactid,'#','')) IN (
    SELECT TRIM(REPLACE(ConvertedContactId,'#','')) FROM Lead WHERE TRIM(REPLACE(Id,'#',''))=TRIM(REPLACE('00QWt0000089AekMAE','#',''))
  )
)
ORDER BY em.messagedate DESC
LIMIT 50;

